import{z as e}from"zod";export const TimelineAnchorSchema=e.object({id:e.string(),chapterIndex:e.number().int().min(0),label:e.string(),inStoryTime:e.string().optional(),characters:e.array(e.string()).default([]),location:e.string().optional(),anchorType:e.enum(["event","milestone","flashback","flashforward","timeskip"]).default("event"),significance:e.number().min(0).max(1).default(.5),createdAt:e.string()});
